/*global require*/
import React, { Children, createContext, useContext, useEffect, useRef, useState } from 'react';
import { Link } from 'gatsby';
import Icon from '@components/ui/Icon';
import BrowserOnly from '@components/BrowserOnly';
import BottomSheet from '@containers/BottomSheet';
// import BrokerSelector from '@appSharedComponents/BrokerSelector';
import TradeHistory from '@appSharedComponents/TradeHistory';
// import UserDropDown from '@components/User/UserDropdown';
import { hdr as hdrId, logoC as logoId, navMenu as navMenuId, active as activeClass } from './header.module.css';
// import logo from '../../images/logo.png';

/** Website header navbar */
export default function Header() {
	return (
		<header id={hdrId}>
			<div id={logoId}>
				<Link to="/">
					<img src="/img/logo.svg" alt="Kaagzi" />
				</Link>
			</div>

			<nav id={navMenuId}>
				<ul>
					<li>
						<Link activeClassName={activeClass} to="/">
							<Icon icon="home2" />
							<span>Home</span>
						</Link>
					</li>
					<li>
						<Link activeClassName={activeClass} to="/app">
							<Icon icon="smartphone" />
							<span>App</span>
						</Link>
					</li>
					<li>
						<Link activeClassName={activeClass} to="/pricing">
							<Icon icon="rupee-sign" />
							<span>Pricing</span>
						</Link>
					</li>
					<li>
						<Link activeClassName={activeClass} partiallyActive={true} to="/guide">
							<Icon icon="book-open" />
							<span>Guide</span>
						</Link>
					</li>
					<li>
						{/* <UserDropDown /> */}
						{/* <BrowserOnly>{() => <UserDropDown />}</BrowserOnly> */}
						<BrowserOnly>
							{() => {
								const UserDropDown = require('@components/userControlPanel/UserDropdown').default;
								return <UserDropDown />;
							}}
						</BrowserOnly>
					</li>
				</ul>
			</nav>
			{/*<span>Search</span>*/}
		</header>
	);
}

/**
 * Header navbar to be used in app screens.
 * Note that the TradeHistory component relies on AppDataIndexedDb proider and thus this component should be imported in the ositions component or any component which is a child of the mentioned provider
 * @param {Object} props React props passed to this component
 * @param {('Zerodha'| 'Angel One'| 'Upstox'| 'Alice Blue')} props.broker Stock Broker
 * @param {string} props.brokerLoggedInUserName Name of user logged in with broker
 * @param {?()=>{}} [props.brokerLogOut] Logout function in case we login user with broker with API
 * @param {?()=>{}} [props.doOnWatchListBtnClick] Callback fn to execute on watchlist button click
 */
export function AppHeader({ broker, brokerLoggedInUserName, brokerLogOut, doOnWatchListBtnClick }) {
	const [isTradeHistoryViz, setIsTradeHistoryViz] = useState(false);
	return (
		<>
			<header id={hdrId}>
				<div id={logoId}>
					<Link to="/">
						<img src="/img/logo.svg" alt="Kaagzi" />
					</Link>
				</div>

				<nav id={navMenuId}>
					<ul>
						<li>
							<BrowserOnly>
								{() => {
									const BrokerSelector = require('@appSharedComponents/BrokerSelector').default;
									return <BrokerSelector broker={broker} brokerLoggedInUserName={brokerLoggedInUserName} brokerLogOut={brokerLogOut} />;
								}}
							</BrowserOnly>
						</li>
						{doOnWatchListBtnClick && typeof doOnWatchListBtnClick === 'function' && (
							<li>
								<button onClick={doOnWatchListBtnClick}>
									<Icon icon="binocular" />
									<span>Watchlist</span>
								</button>
							</li>
						)}
						{/* {doOnTradeHistoryBtnClick && typeof doOnTradeHistoryBtnClick === 'function' && (
						<li>
							<button onClick={doOnTradeHistoryBtnClick}>
								<Icon icon="rupee-sign" />
								<span>Trade History</span>
							</button>
						</li>
					)} */}
						<li>
							<button
								onClick={() => {
									setIsTradeHistoryViz(true);
								}}
							>
								<Icon icon="trade-history" />
								<span>Trade History</span>
							</button>
						</li>
						{/* <li>
						<Link activeClassName={activeClass} partiallyActive={true} to="/guide">
							<Icon icon="book-open" />
							<span>Guide</span>
						</Link>
					</li> */}
						<li>
							{/* <UserDropDown /> */}
							{/* <BrowserOnly>{() => <UserDropDown />}</BrowserOnly> */}
							<BrowserOnly>
								{() => {
									const UserDropDown = require('@components/userControlPanel/UserDropdown').default;
									return <UserDropDown />;
								}}
							</BrowserOnly>
						</li>
					</ul>
				</nav>
				{/*<span>Search</span>*/}
			</header>
			{isTradeHistoryViz && (
				<BottomSheet
					title="Trade History"
					doOnClose={() => {
						setIsTradeHistoryViz(false);
					}}
				>
					{(close) => <TradeHistory closeTradeHistory={close} />}
				</BottomSheet>
			)}
		</>
	);
}

