export default function ColoredNumberDisplay({ currentVal, baseVal, additionalClassWhenGreen, additionalClassWhenRed }) {
	return (
		<span
			className={
				currentVal !== null && baseVal !== null
					? Number(currentVal) >= Number(baseVal) //if currentVal greater than baseVal
						? `${styles.isGreen}${additionalClassWhenGreen ? ' ' + additionalClassWhenGreen : ''}` //+' positive' //'positive' class can be used to further style the value, for eg, prefixing '+' or rupee symbol to this via css
						: `${styles.isRed}${additionalClassWhenRed ? ' ' + additionalClassWhenRed : ''}` //+ ' negative'
					: '' //if value is not present, then default to no specific color
			}
		>
			{/* {currentVal ? Number.parseFloat(currentVal).toFixed(2) : '-.--'} */}
			{currentVal !== null ? formatPriceInIndianStyle(Number(currentVal)) : '-.--'}
			{/* {currentVal == 0 ? '0.00' : currentVal !== null ? formatPriceInIndianStyle(Number(currentVal)) : '-.--'} */}
		</span>
	);
}
