export function Seo_noIndex({ title, description, children }) {
	const {
		siteName,
		title: defaultTitle,
		description: defaultDescription,
		// featuredImage: defaultFeaturedImage,
		favicon,
		themeColor,
	} = useSiteMetadata();

	const seoTitle = title ? siteName + ' | ' + title : defaultTitle,
		seoDesc = description || defaultDescription;
	return (
		<>
			<title>{seoTitle}</title>
			<meta name="description" content={seoDesc} />
			{/* <meta name="image" content={seoImg} /> */}
			<link rel="icon" href={favicon} type="image/x-icon" />
			{/* <link rel="canonical" href={url} /> */}
			<meta name="theme-color" content={themeColor}></meta>
			<meta property="og:title" content={seoTitle} />
			<meta property="og:description" content={seoDesc} />
			{/* <meta property="og:image" content={seoImg} />
			<meta property="og:url" content={url} /> */}
			<meta name="robots" content="noindex" />
			{children}
		</>
	);
}
