import React, { useContext, useEffect, useState } from 'react';

// import { chromeWebExtension_UUID, firefoxWebExtension_UUID } from '@webextensionConfig';

import ColoredNumberDisplay from '@appSharedComponents/ColoredNumberDisplay';
// import PreventRerenderIfValueInvalid from '@components/PreventRerenderIfValueInvalid';
import Button from '@components/ui/Button';
// import Pagination from '@components/Pagination';
import Pagination from '@components/Pagination';
import Loading from '@components/ui/Loading';
import EmptyGfx from '@appSharedComponents/EmptyGfx';
import ConfirmationDialog from '@components/ConfirmationDialog';

import { ToastNotificationContext } from '@providers/ToastNotification';
// import { NetworkCheckContext } from '@providers/NetworkAvailabilityCheck';
import { UserContext } from '@providers/User';
// import { KiteWebSocketContext } from '@kiteProviders/KiteWebSocket';
// import { TabsSwitcherContext } from '@containers/Tabs';

import { AppDataIndexedDbContext } from '@appSharedProviders/AppIndexedDb';

import * as styles from './tradeHistory.module.css';

//==========================+
//		TYPE DEFINITIONS	|
//==========================+

/** @typedef {import('@types_appShared').ClosedPosition} ClosedPosition Broker agnostic closed-position data stored in 'trade-history' objectStore / table */

//======================+
//		COMPONENT		|
//======================+

/**
 * Displays Trade History
 * @param {Object} prop Prop object passed to this component
 * @param {?()=>{}} [prop.closeTradeHistory] Callback fn that can be used to close this trade-history (For eg, useful to close the bottom sheet)
 */
export default function TradeHistory({ closeTradeHistory }) {
	const [isWip, setIsWip] = useState(true); //we start with true & then shall set this to false once first-read from DB is done
	const [tradesAry, setTradesAry] = useState(/** @type {ClosedPosition[]} */ ([]));
	const [totalTrades, setTotalTrades] = useState(0);
	const [totalPages, setTotalPages] = useState(0);
	const [currentPage, setCurrentPage] = useState(1);
	const [showClearHistoryDelConfrmtnDlg, setShowClearHistoryDelConfrmtnDlg] = useState(false);

	const { notify } = useContext(ToastNotificationContext);
	const { checkIfPlanActive } = useContext(UserContext);
	const { getTradeHistory, clearEntireTradeHistory } = useContext(AppDataIndexedDbContext);

	/**
	 * Gets trades from trade-history IndexedDB for the currently active page
	 * @returns {Promise<boolean>} TRUE if read successful, FALSE otherwise
	 */
	const getTradeHistoryForCurrentlyActivePageNum_n_loadIntoState = async () => {
		try {
			const isPlanActive = await checkIfPlanActive(); //this shall cause the 'PlaneExpiryGateway' component to not render this component and display plan expired dialog
			if (!isPlanActive) throw new Error('Plan Expired!');
			setIsWip(true);
			const dataObj = await getTradeHistory(currentPage, 20);
			// console.log(dataObj);
			if (!dataObj) throw new Error('Trade history is empty');
			if (!Object.prototype.hasOwnProperty.call(dataObj, 'records') || dataObj.records.length < 1) throw new Error('No trades found');
			if (!Object.prototype.hasOwnProperty.call(dataObj, 'totalPages')) throw new Error('Error inferring number of trades');
			setTradesAry(dataObj.records);
			setTotalPages(dataObj.totalPages);
			setTotalTrades(dataObj.totalRecords);
			return true;
		} catch (err) {
			// console.error(err);
			notify(err.message || 'Error reading trade-history records', 'err');
			setTradesAry([]);
			return false;
		} finally {
			setIsWip(false);
		}
	};

	// const removeTrade = () => {};

	/** Clears trade history
	 * @returns {Boolean} TRUE if history cleared successfully, FALSE otherwise
	 */
	const clearTradeHistory = async () => {
		try {
			const isPlanActive = await checkIfPlanActive(); //this shall cause the 'PlaneExpiryGateway' component to not render this component and display plan expired dialog
			if (!isPlanActive) throw new Error('Plan Expired!');
			setIsWip(true);
			const opSts = await clearEntireTradeHistory();
			if (!opSts) throw new Error();
			setTradesAry([]);
			setTotalPages(0);
			setTotalTrades(0);
			setCurrentPage(1);
			return true;
		} catch (err) {
			notify(err.message || 'Error clearing trade-history', 'err');
			return false;
		} finally {
			setIsWip(false);
		}
	};

	useEffect(() => {
		(async () => {
			await getTradeHistoryForCurrentlyActivePageNum_n_loadIntoState();
		})();
	}, [currentPage]); //runs on first mount and then whenever currentPage changes

	return (
		<>
			<div className={styles.tradeHistC}>
				{tradesAry.length > 0 && (
					<div className={styles.tradeHistHdr}>
						{/* <Button variant="tertiary" icon="trash-2" isDark={true} onClick={clearTradeHistory}>Clear All</Button> */}
						<Button
							variant="tertiary"
							icon="trash-2"
							isDark={true}
							onClick={() => {
								setShowClearHistoryDelConfrmtnDlg(true);
							}}
						>
							Clear All
						</Button>
						<span>Total trades: {Intl.NumberFormat('en-IN').format(totalTrades)}</span>
					</div>
				)}
				<div className={styles.tradeHistMain}>
					{tradesAry.length < 1 ? (
						// <div className={styles.noTradesEmptyC}>No trades to display</div>
						<EmptyGfx icon="trade-history" note="No Trades to display" />
					) : (
						<ul className={styles.tradeHistUl}>
							{tradesAry.map((trade, i) => {
								//here check if position is expired
								const { sbl, xh, avg, cp, qty, dir, t, x } = trade;

								//here calculate pnl
								const tradePnl = (dir === 'S' ? avg - cp : cp - avg) * qty;

								return (
									<li key={`${i}:${t}:${xh}:${sbl}:${dir}`} className={dir === 'S' ? styles.isSell : styles.isBuy}>
										<div className={styles.dataRow}>
											<span>{sbl}</span>
											<ColoredNumberDisplay currentVal={tradePnl} baseVal={0} />
										</div>
										<div className={styles.metaDataRow}>
											<span className={styles.qty}>{qty}</span>
											<span className={styles.entry}>{avg}</span>
											<span className={styles.exit}>{cp}</span>
										</div>
									</li>
								);
							})}
						</ul>
					)}
					{totalPages > 1 && (
						<div className={styles.tradeHistFtr}>
							{/* <Button variant="tertiary" onClick={() => {}} icon="chevron-left" isDark={true} />
					<Button variant="tertiary" onClick={() => {}} icon="chevron-right" isDark={true} /> */}
							<Pagination totalPages={totalPages} currentPage={currentPage} goToPage={setCurrentPage} />
						</div>
					)}
				</div>
				{isWip && <Loading />}
			</div>
			{showClearHistoryDelConfrmtnDlg && (
				<ConfirmationDialog
					confirmationNote="Confirm deleting entire trade history?"
					doOnClose={() => {
						setShowClearHistoryDelConfrmtnDlg(false);
					}}
					// doOnConfirm={clearTradeHistory}
					doOnConfirm={() => {
						clearTradeHistory().then((isClearedSuccessfully) => {
							isClearedSuccessfully && closeTradeHistory();
						});
					}}
					confirmBtnText="Delete"
				/>
			)}
		</>
	);
}
