import React, { useContext, useEffect, useState } from 'react';
// import { createPortal } from 'react-dom';

// import { StockMarketBrokerContext } from '@providers/StockMarketBroker';
// import { UserAdminNavbarContext } from '@components/UserAdminNavbar';
import Icon from '@components/ui/Icon';
import Button, { LinkButton } from '@components/ui/Button';
import { Link } from 'gatsby';
import BottomSheet from '@containers/BottomSheet';
import { formatName } from '@utils';

import * as styles from './brokerSelector.module.css';

/**
 * Displays button to select broker to switch to
 * @param {Object} prop Prop passed to this component
 * @param {('Zerodha'| 'Angel One'| 'Upstox'| 'Alice Blue')} prop.broker Stock Broker
 * @param {?string} prop.brokerLoggedInUserName Name of user logged in with broker
 * @param {?()=>{}} [prop.brokerLogOut] Logout function in case we login user with broker with API
 */
export default function BrokerSelector({ broker, brokerLoggedInUserName, brokerLogOut }) {
	const [isSelectionMenuViz, setIsSelectionMenuViz] = useState(false);
	// const { currentBroker } = useContext(StockMarketBrokerContext);
	// const { portalOpeningCntnrElm } = useContext(UserAdminNavbarContext);

	const brokersAry = ['Zerodha', 'Angel One', 'Upstox', 'Alice Blue'];

	return (
		<>
			<div>
				<button
					className={styles.brokerSelectorBtn}
					onClick={() => {
						setIsSelectionMenuViz(!isSelectionMenuViz);
					}}
				>
					{/* <img src="https://lh3.googleusercontent.com/a/ACg8ocIf-pZASZUnKasjXtdmY8Occ35eKXWldFUJV_hHEm5D=s96-c" alt="broker" /> */}
					{broker === 'Zerodha' && <img src="/img/logo-kite.png" alt="Zerodha Kite" />}
					{broker === 'Angel One' && <img src="/img/logo-angelOne.webp" alt="Angel One" />}
					{broker === 'Upstox' && <img src="/img/logo-upstox.webp" alt="Upstox" />}
					<div>{brokersAry.includes(broker) ? broker : 'Choose Broker'}</div>
					<Icon icon="chevron-down" />
				</button>
			</div>
			{isSelectionMenuViz && (
				<BottomSheet
					// title="Switch Broker"
					// desc="Choose your preferred broker"
					doOnClose={() => {
						setIsSelectionMenuViz(false);
					}}
				>
					{brokerLoggedInUserName && (
						<div className={styles.brokerLoginStatus}>
							<div className={styles.brokerDtls}>
								{broker === 'Zerodha' && <img src="/img/logo-kite.png" alt="Zerodha Kite" />}
								{broker === 'Angel One' && <img src="/img/logo-angelOne.webp" alt="Angel One" />}
								{broker === 'Upstox' && <img src="/img/logo-upstox.webp" alt="Upstox" />}
								<div className={styles.brokerLoginUser}>
									<span>Logged into {broker} as</span>
									<span>{formatName(brokerLoggedInUserName)}</span>
								</div>
							</div>
							{brokerLogOut && typeof brokerLogOut === 'function' && (
								<Button variant="primary" size="small" isDark={true} onClick={brokerLogOut}>
									Sign Out
								</Button>
							)}
						</div>
					)}
					<header className={styles.brokerSelectorHdr}>
						<h1>Switch Broker</h1>
						<p>Choose your preferred broker</p>
						{/* <LinkButton variant="secondary" isDark={true} to="/app">
							Choose different broker
						</LinkButton> */}
					</header>
					<div className={styles.brokerSelectorListC}>
						{broker !== 'Upstox' && (
							<div>
								<Link to="/app/upstox">
									<img src="/img/logo-upstox.webp" alt="Upstox" />
									<span>Upstox</span>
								</Link>
							</div>
						)}
						{broker !== 'Angel One' && (
							<div>
								<Link to="/app/angelOne">
									<img src="/img/logo-angelOne.webp" alt="Angel One" />
									<span>Angel One</span>
								</Link>
							</div>
						)}
					</div>
				</BottomSheet>
			)}
		</>
	);
}
